import{_ as t,o as i,c as e,ag as l}from"./chunks/framework.DNt_9s2P.js";const u=JSON.parse('{"title":"AI 機能","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai.md","filePath":"guide/ai.md"}'),o={name:"guide/ai.md"};function r(n,a,d,s,h,p){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="ai-機能" tabindex="-1">AI 機能 <a class="header-anchor" href="#ai-機能" aria-label="Permalink to &quot;AI 機能&quot;">​</a></h1><p>Selah は OpenAI / Google Gemini の API を活用した AI 機能を搭載しています。</p><div class="info custom-block"><p class="custom-block-title">前提条件</p><p>AI 機能を使用するには、設定画面で OpenAI API キーまたは Google Gemini API キーを登録する必要があります。API キーはローカルのキーチェーン / クレデンシャルストアに安全に保存されます。</p></div><h2 id="ai-履修分析" tabindex="-1">AI 履修分析 <a class="header-anchor" href="#ai-履修分析" aria-label="Permalink to &quot;AI 履修分析&quot;">​</a></h2><p><strong>場所</strong>: 時間割ビュー</p><p>成績・履修状況・シラバスを基に、包括的な履修アドバイスレポートを生成します。</p><ul><li>卒業要件に対する現在の進捗分析</li><li>不足している単位系列の指摘</li><li>おすすめ科目の提案</li><li>履修バランスの評価</li></ul><h2 id="ai-学習アシスト" tabindex="-1">AI 学習アシスト <a class="header-anchor" href="#ai-学習アシスト" aria-label="Permalink to &quot;AI 学習アシスト&quot;">​</a></h2><p><strong>場所</strong>: TODO ページ</p><p>時間割・シラバス・締切を踏まえた学習計画を生成します。</p><ul><li>タスクごとの優先度判定</li><li>各課題への取り組み方ガイド</li><li>時間配分のアドバイス</li><li>結果は 6 時間キャッシュされ、頻繁な API コールを抑制</li></ul><h2 id="ai-通知サマリー" tabindex="-1">AI 通知サマリー <a class="header-anchor" href="#ai-通知サマリー" aria-label="Permalink to &quot;AI 通知サマリー&quot;">​</a></h2><p><strong>場所</strong>: お知らせページ</p><p>重要な通知の本文を自動取得し、要点とアクション項目を AI で抽出します。</p><ul><li>長文のお知らせをコンパクトに要約</li><li>必要なアクション（提出物、出席確認など）を自動抽出</li><li>見落としを防ぐための要約通知</li></ul><h2 id="対応モデル" tabindex="-1">対応モデル <a class="header-anchor" href="#対応モデル" aria-label="Permalink to &quot;対応モデル&quot;">​</a></h2><table tabindex="0"><thead><tr><th>プロバイダ</th><th>対応モデル</th></tr></thead><tbody><tr><td>OpenAI</td><td>GPT-4o, GPT-4o mini, etc.</td></tr><tr><td>Google</td><td>Gemini Pro, Gemini Flash, etc.</td></tr></tbody></table><p>使用するモデルは設定画面から選択できます。</p>',18)])])}const A=t(o,[["render",r]]);export{u as __pageData,A as default};
